1.query:
timeseries { requestCount_timeseries = sum(dt.service.request.count, scalar: true) },
  by: { dt.smartscape.service, dt.service.name },
  filter: isNotNull(dt.smartscape.service) and in(dt.service.name, {"auth-service","account-service","transaction-service","notification-service","api-gateway"})

| lookup [

// p50 (tendencia)
timeseries Latencia_Promedio = percentile(dt.service.request.response_time, 50),
   by: { dt.smartscape.service }, bins: 40
], sourceField:dt.smartscape.service, lookupField:dt.smartscape.service, fields:{Latencia_Promedio}, executionOrder:leftFirst
| lookup [

// p50 valor reciente
timeseries Latencia = percentile(dt.service.request.response_time, 50),
   by: { dt.smartscape.service }, from: -10m, to: -2m, interval: 1m
| fieldsAdd Latencia = arrayLast(arrayRemoveNulls(Latencia))
], sourceField:dt.smartscape.service, lookupField:dt.smartscape.service, fields:{Latencia}, executionOrder:leftFirst
| lookup [

// Calls (tendencia)
timeseries Calls = sum(dt.service.request.count),
   by: {dt.smartscape.service }, bins: 40
], sourceField:dt.smartscape.service, lookupField:dt.smartscape.service, fields:{Calls}, executionOrder:leftFirst
| lookup [

// Calls valor reciente
timeseries Call = sum(dt.service.request.count),
   by: {dt.smartscape.service }, from: -10m, to: -2m, interval: 1m
| fieldsAdd Call = arrayLast(arrayRemoveNulls(Call))
], sourceField:dt.smartscape.service, lookupField:dt.smartscape.service, fields:{Call}, executionOrder:leftFirst
| lookup [
  // Error rate (tendencia)
      timeseries {
        operand1 = sum(dt.service.request.failure_count),
        operand2 = sum(dt.service.request.count)
      }, by: { dt.smartscape.service }, bins: 40
      | fieldsAdd Errores = operand1[] / operand2[]  * 100
      | fieldsRemove operand1, operand2
], sourceField:dt.smartscape.service, lookupField:dt.smartscape.service, fields:{Errores}, executionOrder:leftFirst
| lookup [
  // Error rate valor reciente
      timeseries {
        operand1 = sum(dt.service.request.failure_count),
        operand2 = sum(dt.service.request.count)
      }, by: { dt.smartscape.service }, from: -10m, to: -2m, interval: 1m
      | fieldsAdd Error_reciente = operand1[] / operand2[]  * 100
      | fieldsAdd Error_reciente = arrayLast(arrayRemoveNulls(Error_reciente))
      | fieldsRemove operand1, operand2
], sourceField:dt.smartscape.service, lookupField:dt.smartscape.service, fields:{Error_reciente}, executionOrder:leftFirst

| fieldsAdd Servicio = coalesce(dt.service.name, dt.smartscape.service)
| fieldsAdd timeframe = timeframe(from: now()-30m, to: now()), interval = (now()-30m-now())/40
| fields Servicio, Errores, Error_reciente, Latencia_Promedio, Latencia, Calls, Call, timeframe, interval
| sort Error_reciente desc
